const p = $json.profile || {};
const h = (p.height_cm || 0) / 100;
const w = Number(p.weight_kg || 0);
const bmi = (h > 0) ? +(w / (h*h)).toFixed(1) : null;
const risks = [];
if (bmi && bmi >= 30) risks.push('weight_management_risk:high');
else if (bmi && bmi >= 25) risks.push('weight_management_risk:moderate');
if ((p.family_history || '').toLowerCase().includes('diabetes')) risks.push('diabetes_lifestyle_risk:elevated');
if ((p.activity_level || '').toLowerCase() === 'low') risks.push('low_activity_risk:elevated');
if (p.age >= 45) risks.push('cardiometabolic_prevention_focus:recommended');
return [{ json: { ...$json, bmi, wellness_risks: risks } }];
